import{c as t,Q as d,j as o,m as r}from"./chunks/framework.CTNaDwNv.js";const b=JSON.parse('{"title":"Tool catalog","description":"","frontmatter":{},"headers":[],"relativePath":"reference/tools.md","filePath":"reference/tools.md","lastUpdated":1779853631000}'),c={name:"reference/tools.md"};function a(l,e,s,n,i,h){return d(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="tool-catalog" tabindex="-1">Tool catalog <a class="header-anchor" href="#tool-catalog" aria-label="Permalink to &quot;Tool catalog&quot;">​</a></h1><p>Every tool input is a strict zod schema. Every tool output follows the <a href="/5m-mcp/reference/envelope">envelope shape</a>. Reflective dispatchers (<code>*_call_*</code>) apply a readonly verb gate (<code>Get/Has/Is/Does/Can/Will/Network</code> always allowed; others require <code>agent_api_readonly=false</code>).</p><h2 id="core-read" tabindex="-1">Core (read) <a class="header-anchor" href="#core-read" aria-label="Permalink to &quot;Core (read)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>health</code></td><td>Liveness probe + version + uptime</td></tr><tr><td><code>list_resources</code></td><td>Every registered resource with state</td></tr><tr><td><code>get_resource_state</code></td><td>One resource&#39;s state + filesystem path</td></tr><tr><td><code>read_file</code></td><td>Read from any resource; <code>offset</code> + <code>length</code> for windowed reads of large files</td></tr><tr><td><code>tail_console</code></td><td>Recent lines from the in-memory ring buffer; filterable by <code>since_ts</code> or <code>channel</code></td></tr><tr><td><code>list_plugins</code></td><td>Loader snapshot — which plugins enabled, which tools each added</td></tr></tbody></table><h2 id="core-write-lifecycle" tabindex="-1">Core (write + lifecycle) <a class="header-anchor" href="#core-write-lifecycle" aria-label="Permalink to &quot;Core (write + lifecycle)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Gated by</th></tr></thead><tbody><tr><td><code>write_file</code></td><td>Write inside a configured write root</td><td><code>readonly</code></td></tr><tr><td><code>create_resource</code></td><td>Scaffold <code>fxmanifest.lua</code> + <code>server.lua</code> + <code>README.md</code></td><td><code>readonly</code></td></tr><tr><td><code>refresh_resources</code></td><td><code>ExecuteCommand(&quot;refresh&quot;)</code> + capture window</td><td>ACE <code>command.refresh</code></td></tr><tr><td><code>ensure_resource</code></td><td><code>ensure &lt;name&gt;</code>, wait for state <code>started</code>, return logs</td><td>ACE + per-resource lock</td></tr><tr><td><code>start_resource</code> / <code>stop_resource</code> / <code>restart_resource</code></td><td>Lifecycle verbs</td><td>ACE + lock + self-target guard</td></tr><tr><td><code>run_command</code></td><td>Allowlisted console command (<code>refresh</code>, <code>players</code>, <code>say &lt;text&gt;</code>, lifecycle verbs)</td><td>ACE + parsed allowlist</td></tr><tr><td><code>run_shell</code></td><td>Allowlisted shell binary inside a resource folder</td><td><code>readonly</code> + shell allowlist + sandboxed <code>cwd</code></td></tr></tbody></table><h2 id="live-player-testing" tabindex="-1">Live player testing <a class="header-anchor" href="#live-player-testing" aria-label="Permalink to &quot;Live player testing&quot;">​</a></h2><p>The opt-in chat command <code>/agent_test_optin</code> lets a player join the test subject pool. TTL: <code>agent_api_test_session_ttl_seconds</code>. Pool size: <code>agent_api_test_max_subjects</code>.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>list_players</code></td><td>Opted-in players with TTL countdown + active-subject flag</td></tr><tr><td><code>register_test_subject</code></td><td>Move opted-in player into the active pool</td></tr><tr><td><code>unregister_test_subject</code></td><td>Remove from active pool (opt-in preserved)</td></tr><tr><td><code>get_player_state</code></td><td>Run predefined client probes (entity, ped, meta, optional inventory)</td></tr><tr><td><code>trigger_client_event</code></td><td>Fire any net event at one subject</td></tr><tr><td><code>send_chat</code></td><td>Push a <code>chat:addMessage</code> line to one subject</td></tr><tr><td><code>wait_for_client_event</code></td><td>Block until matching net event (optional <code>fromSubject</code> filter)</td></tr></tbody></table><h2 id="dynamic-natives" tabindex="-1">Dynamic natives <a class="header-anchor" href="#dynamic-natives" aria-label="Permalink to &quot;Dynamic natives&quot;">​</a></h2><p>Run any FiveM native by name. Read-only verbs always pass; mutators need <code>readonly=false</code>; some natives are hard-blocked.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>server_call_native</code></td><td>Invoke any server-side global function by name; hard-blocks <code>DropPlayer</code>/<code>ExecuteCommand</code>/<code>StopResource</code>/<code>StartResource</code>/<code>BanPlayer</code>/etc</td></tr><tr><td><code>server_list_natives</code></td><td>Enumerate server global function names; filter by substring</td></tr><tr><td><code>client_call_native</code></td><td>Invoke any client native on one active subject. Special arg tokens <code>$ped</code>, <code>$player</code>, <code>$serverId</code>, <code>$vehicle</code>, <code>$lastVehicle</code>, <code>$coords</code>, <code>$heading</code> are resolved client-side</td></tr><tr><td><code>client_list_natives</code></td><td>Enumerate client global function names on the subject</td></tr></tbody></table><h2 id="nui-screenshots" tabindex="-1">NUI screenshots <a class="header-anchor" href="#nui-screenshots" aria-label="Permalink to &quot;NUI screenshots&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>screenshot_nui</code></td><td>Capture the FiveM CEF NUI via CDP at <code>http://localhost:13172</code>. <code>mode = isolate | clip | full</code>. With <code>resource</code> + default <code>isolate</code>, hides sibling iframes for a clean capture and restores them after</td></tr><tr><td><code>delete_screenshot</code></td><td>Remove a screenshot under <code>dist/screenshots/</code> (sandboxed)</td></tr></tbody></table><h2 id="esx-plugin" tabindex="-1">ESX plugin <a class="header-anchor" href="#esx-plugin" aria-label="Permalink to &quot;ESX plugin&quot;">​</a></h2><p>Detects <code>es_extended</code>. Always exposes:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>esx_list_players</code></td><td>All online ESX players (identifier, money, accounts, job)</td></tr><tr><td><code>esx_get_player</code></td><td>Snapshot one xPlayer by server id</td></tr><tr><td><code>esx_list_shared_methods</code></td><td>Discover every callable method on the ESX shared object</td></tr><tr><td><code>esx_list_player_methods</code></td><td>Discover every method on a specific xPlayer (e.g. <code>getInventory</code>)</td></tr><tr><td><code>esx_call_shared</code></td><td>Reflective: call <code>ESX.&lt;method&gt;(...args)</code></td></tr><tr><td><code>esx_call_player</code></td><td>Reflective: call <code>xPlayer.&lt;method&gt;(...args)</code></td></tr></tbody></table><p>With <code>readonly=false</code>, also:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>esx_add_money</code></td><td>Add to a money account (<code>cash</code> / <code>bank</code> / <code>black_money</code>)</td></tr><tr><td><code>esx_set_job</code></td><td>Assign job + grade</td></tr></tbody></table><h2 id="ox-lib-plugin" tabindex="-1">ox_lib plugin <a class="header-anchor" href="#ox-lib-plugin" aria-label="Permalink to &quot;ox_lib plugin&quot;">​</a></h2><p>Detects <code>ox_lib</code>. Uses <code>@overextended/ox_lib/server</code> for typed access.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>oxlib_notify</code></td><td>Push an ox_lib UI notification to one player</td></tr><tr><td><code>oxlib_trigger_client_callback</code></td><td>Round-trip request/response via <code>lib.callback</code></td></tr><tr><td><code>oxlib_check_dependency</code></td><td><code>versionCheck(&quot;resource@x.y.z&quot;)</code></td></tr><tr><td><code>oxlib_list_methods</code></td><td>Enumerate exported functions + namespaces</td></tr><tr><td><code>oxlib_call</code></td><td>Reflective dotted-path invocation (<code>addAce</code>, <code>cache.serverId</code>, etc.)</td></tr></tbody></table><h2 id="oxmysql-plugin" tabindex="-1">oxmysql plugin <a class="header-anchor" href="#oxmysql-plugin" aria-label="Permalink to &quot;oxmysql plugin&quot;">​</a></h2><p>Detects <code>oxmysql</code>. Uses <code>@overextended/oxmysql</code> for typed access. Defaults to <code>SELECT</code>-only; expand via <code>agent_api_plugin_oxmysql_readonly=false</code> and <code>agent_api_plugin_oxmysql_allow_statements</code>.</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>oxmysql_query</code></td><td><code>oxmysql.query</code> returning a rows array (auto-trimmed to <code>rowLimit</code>, default 100)</td></tr><tr><td><code>oxmysql_scalar</code></td><td><code>oxmysql.scalar</code> returning the first column of the first row</td></tr><tr><td><code>oxmysql_execute</code></td><td><code>oxmysql.rawExecute</code> for INSERT/UPDATE/DELETE/DDL when allowed</td></tr></tbody></table><h2 id="workflow-meta" tabindex="-1">Workflow / meta <a class="header-anchor" href="#workflow-meta" aria-label="Permalink to &quot;Workflow / meta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>scaffold_fivem_resource_workflow</code></td><td><strong>Mandatory pre-flight</strong> for new-resource intent. Returns the full grill workflow text. Engineered description so the agent auto-calls it before <code>create_resource</code> / <code>write_file</code></td></tr></tbody></table>',27)])])}const p=t(c,[["render",a]]);export{b as __pageData,p as default};
